from agent import *from models.products import *def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.queue(Request('http://xbox-mag.net/tests/'), process_revlist, {})def process_revlist(data, context, session):    for rev in data.xpath("//div[@class='liste-jeux-infos']/p[@class='titre-jeu']"):        url = rev.xpath("descendant::a/@href").string()        title = rev.xpath("descendant::text()").string()        categorytxt = rev.xpath("preceding-sibling::p[@class='support']/text()").string(multiple=True)        if url and title and categorytxt:            name = re_search_once(': (.*)$', title)            catlist = []            cats = categorytxt.split('/')            for cat in cats:                catlist.append(cat.strip())            category = "|".join(catlist)            session.queue(Request(url), process_product, dict(url=url, name=name, category=category))    nexturl = data.xpath("//a[@class='next']/@href").string()    if nexturl:        session.queue(Request(nexturl), process_revlist, dict())def process_product(data, context, session):    product = Product()    product.name = context['name']    product.url = context['url']    product.ssid = context['url'].split('jeux/')[-1].split('/test')[0]    category = context['category'].replace('Retail', 'Games')    if not category.startswith('Games'):        if not category.startswith('|'):            category = 'Games|' + category        else:            category = 'Games' + category    if category == 'Games|':        category = 'Games'    product.category = category    manufacturer_info = data.xpath("//div[@id='bandeau-content']//p[@class='details']//text()")    for man in range(len(manufacturer_info)):        if 'Edité par' in manufacturer_info[man].string():            product.manufacturer = manufacturer_info[man + 1].string().strip()            break    for rev in data.xpath("//div[@class='liste-articles-infos-content']/a"):        url = rev.xpath("@href").string()        title = rev.xpath("@title").string(multiple=True)        if url and title:            session.do(Request(url), process_review, dict(product=product, url=url))    if not data.xpath("//div[@class='liste-articles-infos-content']/a"):        process_review(data, dict(product=product, url=product.url), session)    if product.reviews:        session.emit(product)def process_review(data, context, session):    product = context['product']    content = data.xpath("//div[@class='page-content box-content-shadow']").first()    if not content:        return        review = Review()    review.type = 'pro'    review.title = content.xpath("descendant::h2/text()").string()    review.url = context['url']    if ' sur ' in review.title and product.category == 'Games':        product.category = 'Games|' + review.title.split(' sur ')[1]    ssid = review.url.split('jeux/')[-1].replace('/', '-')    if ssid.endswith('-'):        ssid = ssid[:-1]    review.ssid = ssid    date = content.xpath("descendant::span[@class='date']/text()").string(multiple=True)    if date:        review.date = date.split(' ')[0]        author = content.xpath("descendant::span[@class='auteur']/a").first()    if author:        url = author.xpath("@href").string()        name = author.xpath("descendant::text()").string(multiple=True)        if url and name:            review.authors.append(Person(name=name, ssid=name, profile_url=url))    summary = content.xpath("descendant::div[@class='introduction']//text()").string(multiple=True)    if summary:        review.properties.append(ReviewProperty(type='summary', value=summary))    excerpt = content.xpath("div[@class='article-texte']/p//text()").string(multiple=True)    if not excerpt:        excerpt = content.xpath("div[@class='article-texte']//p//text()").string(multiple=True)    if excerpt:        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))    rate = content.xpath("descendant::div[@class='note']//span/text()").string()    if not rate:        rate = data.xpath("//div[@class='note']//span/text()").string()    if rate:        if rate != '-':            rate = rate.split('/')[0]            review.grades.append(Grade(type='overall', value=float(rate), best=10.0))    for pro in content.xpath("descendant::div[@class='plusmoins']/div[@class='pull-left']//ul/li"):        line = pro.xpath("descendant::text()").string(multiple=True)        if line:            review.properties.append(ReviewProperty(type='pros', value=line))    for con in content.xpath(" descendant::div[@class='plusmoins']/div[@class='pull-right']//ul/li"):        line = con.xpath("descendant::text()").string(multiple=True)        if line:            review.properties.append(ReviewProperty(type='cons', value=line))    conclusion = content.xpath(" descendant::div[@class='conclusion']//text()").string(multiple=True)    if conclusion:        review.properties.append(ReviewProperty(type='conclusion', value=conclusion))    if excerpt or summary or conclusion:        product.reviews.append(review)